// DOM ready
(function() {
    'use strict';
  
    // Mobile menu toggle
    var menuToggle = document.getElementById('menuToggle');
    var navLinks = document.getElementById('navLinks');
    if (menuToggle) {
      menuToggle.addEventListener('click', function() {
        navLinks.classList.toggle('active');
      });
    }
  
    // Scroll reveal mượt mà
    var revealElements = document.querySelectorAll('.benefit-card, .section-card, .step, .faq-item, .cta-simple');
    
    var revealOnScroll = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.classList.add('reveal-card');
          revealOnScroll.unobserve(entry.target);
        }
      });
    }, { threshold: 0.15, rootMargin: "0px 0px -20px 0px" });
    
    revealElements.forEach(function(el) {
      revealOnScroll.observe(el);
    });
    
    // Thêm class cho hero
    var heroContent = document.querySelector('.hero-content');
    var heroVisual = document.querySelector('.hero-visual');
    if (heroContent) heroContent.classList.add('fade-up-init');
    if (heroVisual) heroVisual.classList.add('fade-up-init');
    
    if (heroContent) revealOnScroll.observe(heroContent);
    if (heroVisual) revealOnScroll.observe(heroVisual);
    
    // FAQ Accordion
    var faqItems = document.querySelectorAll('.faq-item');
    faqItems.forEach(function(item) {
      var questionDiv = item.querySelector('.faq-question');
      if (questionDiv) {
        questionDiv.addEventListener('click', function() {
          item.classList.toggle('active');
          var icon = questionDiv.querySelector('i');
          if (item.classList.contains('active')) {
            icon.classList.remove('fa-chevron-down');
            icon.classList.add('fa-chevron-up');
          } else {
            icon.classList.remove('fa-chevron-up');
            icon.classList.add('fa-chevron-down');
          }
        });
      }
    });
  
    // Smooth scroll
    var allLinks = document.querySelectorAll('a[href^="#"]');
    allLinks.forEach(function(anchor) {
      anchor.addEventListener('click', function(e) {
        var targetId = this.getAttribute('href');
        if (targetId === "#") return;
        var target = document.querySelector(targetId);
        if (target) {
          e.preventDefault();
          target.scrollIntoView({ behavior: 'smooth', block: 'start' });
          if (navLinks && navLinks.classList.contains('active')) {
            navLinks.classList.remove('active');
          }
        }
      });
    });
    
    // Khởi tạo reveal cho hero sau 100ms
    setTimeout(function() {
      var heroContentEl = document.querySelector('.hero-content');
      var heroVisualEl = document.querySelector('.hero-visual');
      if (heroContentEl) heroContentEl.classList.add('reveal');
      if (heroVisualEl) heroVisualEl.classList.add('reveal');
    }, 100);
  })();